public boolean sumWithReverse(int num) {
    for (int i = 0; i <= num; i++) {
        int reverse = 0, temp = i;
        while (temp != 0) {
            reverse = reverse * 10 + temp % 10;
            temp /= 10;
        }
        if (i + reverse == num) {
            return true;
        }
    }
    return false;
}
```

